//! Config from env or from API request: migrate_from URL, migrate_to_store URL, credentials.
//! Table list is read from the file generated by order-tables (migrate_tables_order.rs) or provided.

use std::env;
use std::path::Path;

pub struct Config {
    pub migrate_from_database_url: String,
    pub migrate_to_store_url: String,
    pub store_account_id: String,
    pub store_account_secret: String,
    pub store_root_account_id: Option<String>,
    pub store_root_account_secret: Option<String>,
    pub tables: Vec<String>,
    pub app_id: String,
    pub error_log_path: String,
    /// When set, rows from the "counters" table are sent to this URL (POST /migrate) instead of the store.
    pub counter_service_url: Option<String>,
    /// Database name (e.g. connectivo, skyll) sent as `database` to the counter service when migrating counters. Required when counter_service_url is set.
    pub migrate_to_database_name: Option<String>,
    /// When set, direct Postgres URL to the destination (store) database. Used to DROP/RECREATE unique indexes before/after migrating each table.
    pub migrate_to_database_url: Option<String>,
    /// Number of rows to fetch from the source DB per batch. From MIGRATE_BATCH_SIZE (default 100).
    pub batch_size: usize,
    /// Max concurrent requests to the store (or counter service) per batch. From MIGRATE_CONCURRENT (default 50). Must not exceed 100.
    pub concurrent: usize,
}

fn parse_batch_size_and_concurrent(
) -> Result<(usize, usize), Box<dyn std::error::Error + Send + Sync>> {
    let batch_size = env::var("MIGRATE_BATCH_SIZE")
        .ok()
        .and_then(|v| v.trim().parse().ok())
        .unwrap_or(100);
    let concurrent = env::var("MIGRATE_CONCURRENT")
        .ok()
        .and_then(|v| v.trim().parse().ok())
        .unwrap_or(50);
    if concurrent > 100 {
        return Err("MIGRATE_CONCURRENT must not be more than 100".into());
    }
    Ok((batch_size, concurrent))
}

impl Config {
    pub fn from_env() -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let migrate_from_database_url = env::var("MIGRATE_FROM_DATABASE_URL")
            .map_err(|_| "MIGRATE_FROM_DATABASE_URL is required")?;
        let migrate_to_store_url =
            env::var("MIGRATE_TO_STORE_URL").map_err(|_| "MIGRATE_TO_STORE_URL is required")?;
        let store_account_id = env::var("MIGRATE_STORE_ACCOUNT_ID")
            .map_err(|_| "MIGRATE_STORE_ACCOUNT_ID is required")?;
        let store_account_secret = env::var("MIGRATE_STORE_ACCOUNT_SECRET")
            .map_err(|_| "MIGRATE_STORE_ACCOUNT_SECRET is required")?;
        let store_root_account_id = env::var("MIGRATE_STORE_ROOT_ACCOUNT_ID").ok();
        let store_root_account_secret = env::var("MIGRATE_STORE_ROOT_ACCOUNT_SECRET").ok();
        let tables_file = env::var("MIGRATE_TABLES_FILE")
            .unwrap_or_else(|_| "migrate_tables_order.rs".to_string());
        let tables = load_tables_from_order_file(&tables_file)?;
        let app_id = env::var("MIGRATE_APP_ID").unwrap_or_else(|_| "portal".to_string());
        let error_log_path = env::var("MIGRATE_ERROR_LOG").unwrap_or_else(|_| {
            std::env::current_dir()
                .map(|d| d.join("migrate_errors.log").to_string_lossy().to_string())
                .unwrap_or_else(|_| "migrate_errors.log".to_string())
        });
        let (batch_size, concurrent) = parse_batch_size_and_concurrent()?;

        Ok(Self {
            migrate_from_database_url,
            migrate_to_store_url: migrate_to_store_url.trim_end_matches('/').to_string(),
            store_account_id,
            store_account_secret,
            store_root_account_id,
            store_root_account_secret,
            tables,
            app_id,
            error_log_path,
            counter_service_url: env::var("MIGRATE_COUNTER_SERVICE_URL").ok(),
            migrate_to_database_name: env::var("MIGRATE_TO_DATABASE_NAME").ok(),
            migrate_to_database_url: env::var("MIGRATE_TO_DATABASE_URL").ok(),
            batch_size,
            concurrent,
        })
    }

    /// Build config from API request parameters (for POST /migrate).
    /// batch_size and concurrent are read from env (MIGRATE_BATCH_SIZE, MIGRATE_CONCURRENT); concurrent must be <= 100.
    pub fn from_request_validate(
        migrate_from_database_url: String,
        migrate_to_store_url: String,
        store_account_id: String,
        store_account_secret: String,
        store_root_account_id: Option<String>,
        store_root_account_secret: Option<String>,
        tables: Vec<String>,
        app_id: Option<String>,
        error_log_path: Option<String>,
        counter_service_url: Option<String>,
        migrate_to_database_name: Option<String>,
        migrate_to_database_url: Option<String>,
    ) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let (batch_size, concurrent) = parse_batch_size_and_concurrent()?;
        Ok(Self::from_request(
            migrate_from_database_url,
            migrate_to_store_url,
            store_account_id,
            store_account_secret,
            store_root_account_id,
            store_root_account_secret,
            tables,
            app_id,
            error_log_path,
            counter_service_url,
            migrate_to_database_name,
            migrate_to_database_url,
            batch_size,
            concurrent,
        ))
    }

    /// Build config from API request parameters (for POST /migrate).
    pub fn from_request(
        migrate_from_database_url: String,
        migrate_to_store_url: String,
        store_account_id: String,
        store_account_secret: String,
        store_root_account_id: Option<String>,
        store_root_account_secret: Option<String>,
        tables: Vec<String>,
        app_id: Option<String>,
        error_log_path: Option<String>,
        counter_service_url: Option<String>,
        migrate_to_database_name: Option<String>,
        migrate_to_database_url: Option<String>,
        batch_size: usize,
        concurrent: usize,
    ) -> Self {
        let migrate_to_store_url = migrate_to_store_url.trim_end_matches('/').to_string();
        Self {
            migrate_from_database_url,
            migrate_to_store_url,
            store_account_id,
            store_account_secret,
            store_root_account_id,
            store_root_account_secret,
            tables,
            app_id: app_id.unwrap_or_else(|| "portal".to_string()),
            error_log_path: error_log_path.unwrap_or_else(|| "migrate_errors.log".to_string()),
            counter_service_url: counter_service_url.map(|u| u.trim_end_matches('/').to_string()),
            migrate_to_database_name: migrate_to_database_name.filter(|s| !s.trim().is_empty()),
            migrate_to_database_url: migrate_to_database_url.filter(|s| !s.trim().is_empty()),
            batch_size,
            concurrent,
        }
    }

    /// Connect to the source (migrate_from) database. Session is set to read-only so
    /// no INSERT/UPDATE/DELETE can run against the source (safe for QA).
    pub async fn connect_postgres(
        &self,
    ) -> Result<tokio_postgres::Client, Box<dyn std::error::Error + Send + Sync>> {
        let url = ensure_sslmode_disable(&self.migrate_from_database_url);
        let (client, connection) = tokio_postgres::connect(&url, tokio_postgres::NoTls).await?;
        tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("postgres connection error: {}", e);
            }
        });
        // Enforce read-only: only SELECT is allowed; mutations will error
        client
            .batch_execute("SET default_transaction_read_only = on")
            .await?;
        Ok(client)
    }

    /// Connect to the destination database (for DDL: drop/recreate unique indexes). Optional.
    pub async fn connect_postgres_destination(
        &self,
    ) -> Result<Option<tokio_postgres::Client>, Box<dyn std::error::Error + Send + Sync>> {
        let url = match &self.migrate_to_database_url {
            Some(u) if !u.trim().is_empty() => u.trim(),
            _ => return Ok(None),
        };
        let url = ensure_sslmode_disable(url);
        let (client, connection) = tokio_postgres::connect(&url, tokio_postgres::NoTls).await?;
        tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("postgres destination connection error: {}", e);
            }
        });
        Ok(Some(client))
    }
}

/// Load table names from the Rust array file generated by order-tables (e.g. migrate_tables_order.rs).
/// Only parses the MIGRATE_TABLES_ORDER array so we do not treat MIGRATE_CIRCULAR_FK_COLS
/// column names (e.g. "account_id", "created_by") as table names.
fn load_tables_from_order_file(
    path: &str,
) -> Result<Vec<String>, Box<dyn std::error::Error + Send + Sync>> {
    let content = std::fs::read_to_string(Path::new(path)).map_err(|e| {
        format!(
            "Failed to read table order file '{}': {}. Run 'make order-tables' first.",
            path, e
        )
    })?;

    let mut tables = Vec::new();
    let mut in_order_array = false;

    for line in content.lines() {
        let trimmed = line.trim();
        // Skip comment-only lines
        if trimmed.starts_with("//") {
            continue;
        }
        // Start collecting after we see MIGRATE_TABLES_ORDER and its opening &[
        if trimmed.contains("MIGRATE_TABLES_ORDER") && trimmed.contains("&[") {
            in_order_array = true;
            // Same line may have first table: &[ "foo",
            if let Some(s) = extract_quoted(trimmed) {
                tables.push(s);
            }
            if trimmed.contains("];") {
                break;
            }
            continue;
        }
        if in_order_array {
            if trimmed.contains("];") {
                if let Some(s) = extract_quoted(trimmed) {
                    tables.push(s);
                }
                break;
            }
            if let Some(s) = extract_quoted(trimmed) {
                tables.push(s);
            }
        }
    }

    if tables.is_empty() {
        return Err(format!(
            "No tables found in MIGRATE_TABLES_ORDER in '{}'. Run 'make order-tables' to generate it.",
            path
        )
        .into());
    }
    Ok(tables)
}

/// Extract the first quoted string from a line (e.g. "organizations", or // "commented" -> None for comment lines).
fn extract_quoted(line: &str) -> Option<String> {
    let open = line.find('"')?;
    let after_open = &line[open + 1..];
    let close = after_open.find('"')?;
    Some(after_open[..close].to_string())
}

/// Append sslmode=disable to the URL if no sslmode is set (avoids "server does not support TLS" for local Postgres).
fn ensure_sslmode_disable(url: &str) -> String {
    if url.contains("sslmode=") {
        url.to_string()
    } else {
        let sep = if url.contains('?') { "&" } else { "?" };
        format!("{}{}sslmode=disable", url, sep)
    }
}
